
%This script uses files generated by TSprocessSpikes
%(animalshank#_units_outputtrack)and clusters Hippocampus units into excitatory units and
%inhibitory units using thresholds for firing rate, mean autocorrelation and CSI. 

%Then makes phase locking polar plots separated by age x genotype groups for each
%region (CA1 or DG), running state (all running, thresholded running, non running, all),
%and cell type (excitatory vs inhibitory). 

%Inputs: Cell array of animal IDs, file paths to kilosort files, out_dir file path to save files to if applicable, overwrite = 0 or 1. If overwrite = 1 the script will re-make/save a
%csv output file, if 0 it will only generate plots.
%Output files from TSprocessSpikes must exist for each animal/shank. User may need to adjust expected file names 
%in the code that loads these files in. 
%script assumes that there is an additional file for each shank containing
%phase locking calculations using alternative hippocampal layers (i.e. not
%CA1 pyramidal layer) as a theta reference but this could be commented out
%if not applicable. 

%Outputs: Makes phase locking plots separated by age/genotype group for each
%layer, running state (all running, thresholded running, non running, all),
%and cell type. I ultimately decided to make plots in R in a different
%format but this may be useful for exploring future data sets. 
%If overwrite = 1 also generates a csv file with a row for
%each unit containing all of that unit's attributes/values for all
%calculated variables. 


%animals = { 'AD-WT-44-1', '3xTg132', '3xTg136' 'WT162' 'WT78-0' '3xTg75-1' 'WT77-0' '3xTg79-0' 'WT89-0' 'WT98-0' '3xTg77-1' 'WT158' 'WT153' 'WT157' '3xTg125' 'WT126' '3xTg123' 'WT45-1' 'WT45-2' 'WT47-0' '3xTg48-0' '3xTg49-2' '3xTg49-1' 'AD-WT-1-0' '3xTg1-1' '3xTg1-2' 'WT159' 'WT105-0' 'WT69-1' 'WT181' 'WT173' '3xTg165' '3xTg177' '3xTg148-1' };
%kilosort_dir = 'Z:\Lauren\Ephys Experiments\Kilosort\'; %location of kilosort/phy files
%out_dir = 'W:\data analysis';
%overwrite = 0; 


function HIPP_SpikeProcessing_LV_all_2023_V3_Aonly(animals, kilosort_dir, out_dir, overwrite)
% %cell regions

DG=[];
CA1=[];

uind=0;  %master unit index

%set up directory with kilosort files
all = dir(fullfile(kilosort_dir,'*')); %all stuff in directory
folder_names = setdiff({all([all.isdir]).name},{'.','..'}); % list of subfolders

for anim=1:length(animals)  %loop through all animals and get info about each cluster from that animal
    
animal=animals{anim};

%These two animals didn't have a usable A1 epoch so I used the 2nd
%presentation of track A isntead
% if strcmp(animal, '3xTg1-2') || strcmp(animal, 'WT181')
%     track = 'A2';
% else
%     track = 'A1';
% end
track = 'all';

%get all available spike sorted shanks for this animal
[HIPshanks, ECshanks]=getshankECHIP_LV_multi(animal);
 

for sh=1:length(HIPshanks) 
shank = HIPshanks(sh); %get units from each shank
[ch] = getchannels_drift(animal, shank, 4);  % get channels from channel set designed to be for spikes

%get info about this animal's sex, group, age 
group = ch.group;
sex = ch.sex;
age = ch.age; 

    %find output files from TSprocessspikes for this animal
    for fold = 1:length(folder_names)  %find folder that has current animal's raw unit files inside - some folders have arbitrary blinded names but have files inside with animal name in them
        all_in_sub = dir(fullfile(kilosort_dir,folder_names{fold},'*')); %stuff in subfolder
        files = {all_in_sub(~[all_in_sub.isdir]).name}; % only files in subfolder.
        file = fullfile(kilosort_dir,folder_names{fold},files{1}); %grab first file
        if contains(file, animal)
        spike_dir = [kilosort_dir folder_names{fold}];
        %cd(spike_dir);
        end
    end  


%load info about units generated by previous script
%TSprocessspikes_LV_full_batch
load([ spike_dir '/' animal 'shank' num2str(shank) '_units_output_allAtrack.mat']) %structure called units_output  

%load in later analyzed data - phase locking to theta in other hipp layers 
load([spike_dir '/' animal 'shank' num2str(shank) '_units_output_PL_LMMolHil_allAtrack.mat'])

%find indices that correspond to each layer

%originally used +/- 3 from region edges, currently testing broader ranges 
if ~isempty(ch.DGlow) && ~isempty (ch.DGup)  %get DG units
DGunits=find(units_output.correctch>=ch.DGlow-3 & units_output.correctch<=ch.DGup+6);  %added +/- 3 to be a little broader
DG=[DG DGunits+uind];
end
if ~isempty(ch.CA1up) && ~isempty (ch.CA1low)   %get CA1 units
CA1units=find(units_output.correctch>=ch.CA1low-10 & units_output.correctch<=ch.CA1up+7);
CA1=[CA1 CA1units+uind];
end



%put spike attributes into master array
    for u=1:length(units_output.meanAC_all)  %getting all the important info about each unit from file we loaded in earlier 
        uind=uind+1;
        
        animal_ind{uind} = animal;  %added this so I can know which animal each cluster belongs to for plotting later
        shank_ind(uind) = shank;
        group_ind{uind} = ch.group;
        sex_ind{uind} = ch.sex;
        age_ind{uind} = ch.age;
        
        %get waveform info for splitting into exc and inh 
        if isnan(units_output.mISI_all(u)) || units_output.numspikes_all(u) < 50  %if there is no value or too few spikes set to NaN
        asym(uind)=NaN;
        c(uind)=NaN;
        a(uind) = NaN;
        b(uind) = NaN;
        else
        asym(uind)=units_output.waveforms{u}.asym;
        c(uind)=units_output.waveforms{u}.c;
        a(uind) = units_output.waveforms{u}.a;
        b(uind) = units_output.waveforms{u}.b;
        end
      
        %get all other attributes by running state
        %all
        if isnan(units_output.mISI_all(u))
        r2CA1theta_all(uind)=NaN;  
        mu2CA1theta_all(uind)=NaN;
        r2MECtheta_all(uind)=NaN;
        mu2MECtheta_all(uind)=NaN;
        
        r2LMtheta_all(uind) = NaN;
        mu2LMtheta_all(uind) = NaN;
        r2Moltheta_all(uind) = NaN;
        mu2Moltheta_all(uind) = NaN;
        r2Hiltheta_all(uind) = NaN;
        mu2Hiltheta_all(uind) = NaN;
        
        r2CA1gamma_all(uind)=NaN;  
        mu2CA1gamma_all(uind)=NaN;
        r2MECgamma_all(uind)=NaN;
        mu2MECgamma_all(uind)=NaN;
        mFR_all(uind)= NaN;
        meanAC_all(uind)=NaN;
        burst_all(uind)=NaN;
        burstbw_all(uind) = NaN;
        mISI_all(uind)=NaN;
        CSI_all(uind)=NaN;
        mAmp_all(uind)=NaN;   
        refvio_all(uind) = NaN;
        
        
        
        elseif ~isnan(units_output.mISI_all(u)) && ECshanks(1) == 0  %if EC shank is  missing set EC PL values to NaN
            
        r2CA1theta_all(uind)=units_output.CA1thetaPL_all{u}.r;   
        mu2CA1theta_all(uind)=units_output.CA1thetaPL_all{u}.mu;
        r2MECtheta_all(uind)=NaN;
        mu2MECtheta_all(uind)=NaN;
        
        r2LMtheta_all(uind) = units_output2.LMthetaPL_all{u}.r; 
        mu2LMtheta_all(uind) = units_output2.LMthetaPL_all{u}.mu; 
        r2Moltheta_all(uind) = units_output2.MolthetaPL_all{u}.r; 
        mu2Moltheta_all(uind) = units_output2.MolthetaPL_all{u}.mu; 
        r2Hiltheta_all(uind) = units_output2.HilthetaPL_all{u}.r; 
        mu2Hiltheta_all(uind) = units_output2.HilthetaPL_all{u}.mu; 
        
        r2CA1gamma_all(uind)=units_output.CA1gammaPL_all{u}.r;   
        mu2CA1gamma_all(uind)=units_output.CA1gammaPL_all{u}.mu;
        r2MECgamma_all(uind)=NaN;
        mu2MECgamma_all(uind)=NaN;
        
        mFR_all(uind)= units_output.mFR_all(u);
        meanAC_all(uind)=units_output.meanAC_all(u);
        burst_all(uind)=units_output.burst_all(u);
        burstbw_all(uind) = units_output.burstbw_all(u);
        mISI_all(uind)=units_output.mISI_all(u);
        CSI_all(uind)=units_output.CSI_all(u);
        mAmp_all(uind)=units_output.mAmp_all(u);
        
        refvio_all(uind)= units_output.refvio_ratio_all(u);    
            
        else
        r2CA1theta_all(uind)=units_output.CA1thetaPL_all{u}.r;   
        mu2CA1theta_all(uind)=units_output.CA1thetaPL_all{u}.mu;
        r2MECtheta_all(uind)=units_output.MECIIthetaPL_all{u}.r;
        mu2MECtheta_all(uind)=units_output.MECIIthetaPL_all{u}.mu;
        
        r2LMtheta_all(uind) = units_output2.LMthetaPL_all{u}.r; 
        mu2LMtheta_all(uind) = units_output2.LMthetaPL_all{u}.mu; 
        r2Moltheta_all(uind) = units_output2.MolthetaPL_all{u}.r; 
        mu2Moltheta_all(uind) = units_output2.MolthetaPL_all{u}.mu; 
        r2Hiltheta_all(uind) = units_output2.HilthetaPL_all{u}.r; 
        mu2Hiltheta_all(uind) = units_output2.HilthetaPL_all{u}.mu; 
        
        r2CA1gamma_all(uind)=units_output.CA1gammaPL_all{u}.r;   
        mu2CA1gamma_all(uind)=units_output.CA1gammaPL_all{u}.mu;
        r2MECgamma_all(uind)=units_output.MECIIgammaPL_all{u}.r;
        mu2MECgamma_all(uind)=units_output.MECIIgammaPL_all{u}.mu;
        
        mFR_all(uind)= units_output.mFR_all(u);
        meanAC_all(uind)=units_output.meanAC_all(u);
        burst_all(uind)=units_output.burst_all(u);
        burstbw_all(uind) = units_output.burstbw_all(u);
        mISI_all(uind)=units_output.mISI_all(u);
        CSI_all(uind)=units_output.CSI_all(u);
        mAmp_all(uind)=units_output.mAmp_all(u);
        
        refvio_all(uind)= units_output.refvio_ratio_all(u);
        end

        %all running
        if isnan(units_output.mISI_all_run(u))
        r2CA1theta_all_run(uind)=NaN;
        mu2CA1theta_all_run(uind)=NaN;
        r2MECtheta_all_run(uind)=NaN;
        mu2MECtheta_all_run(uind)=NaN;
        
        r2LMtheta_all_run(uind) = NaN;
        mu2LMtheta_all_run(uind) = NaN;
        r2Moltheta_all_run(uind) = NaN;
        mu2Moltheta_all_run(uind) = NaN;
        r2Hiltheta_all_run(uind) = NaN;
        mu2Hiltheta_all_run(uind) = NaN;
        
        r2CA1gamma_all_run(uind)=NaN;
        mu2CA1gamma_all_run(uind)=NaN;
        r2MECgamma_all_run(uind)=NaN;
        mu2MECgamma_all_run(uind)=NaN;
        
        mFR_all_run(uind)= NaN;
        meanAC_all_run(uind)=NaN;
        burst_all_run(uind)=NaN;
        burstbw_all_run(uind) = NaN;
        mISI_all_run(uind)=NaN;
        CSI_all_run(uind)=NaN;
        mAmp_all_run(uind)=NaN;
        
        refvio_all_run(uind)= NaN;
        
        elseif ~isnan(units_output.mISI_all(u)) && ECshanks(1) == 0  %if EC shank is  missing set EC PL values to NaN
        r2CA1theta_all_run(uind)=units_output.CA1thetaPL_all_run{u}.r;   
        mu2CA1theta_all_run(uind)=units_output.CA1thetaPL_all_run{u}.mu;
        r2MECtheta_all_run(uind)=NaN;
        mu2MECtheta_all_run(uind)=NaN;
        
        r2LMtheta_all_run(uind) = units_output2.LMthetaPL_all_run{u}.r; 
        mu2LMtheta_all_run(uind) = units_output2.LMthetaPL_all_run{u}.mu; 
        r2Moltheta_all_run(uind) = units_output2.MolthetaPL_all_run{u}.r; 
        mu2Moltheta_all_run(uind) = units_output2.MolthetaPL_all_run{u}.mu; 
        r2Hiltheta_all_run(uind) = units_output2.HilthetaPL_all_run{u}.r; 
        mu2Hiltheta_all_run(uind) = units_output2.HilthetaPL_all_run{u}.mu; 
        
        r2CA1gamma_all_run(uind)=units_output.CA1gammaPL_all_run{u}.r;   
        mu2CA1gamma_all_run(uind)=units_output.CA1gammaPL_all_run{u}.mu;
        r2MECgamma_all_run(uind)=NaN;
        mu2MECgamma_all_run(uind)=NaN;
        
        mFR_all_run(uind)= units_output.mFR_all_run(u);
        meanAC_all_run(uind)=units_output.meanAC_all_run(u);
        burst_all_run(uind)=units_output.burst_all_run(u);
        burstbw_all_run(uind) = units_output.burstbw_all_run(u);
        mISI_all_run(uind)=units_output.mISI_all_run(u);
        CSI_all_run(uind)=units_output.CSI_all_run(u);
        mAmp_all_run(uind)=units_output.mAmp_all_run(u);
        
        refvio_all_run(uind)= units_output.refvio_ratio_all_run(u);
        
        else
        r2CA1theta_all_run(uind)=units_output.CA1thetaPL_all_run{u}.r;   
        mu2CA1theta_all_run(uind)=units_output.CA1thetaPL_all_run{u}.mu;
        r2MECtheta_all_run(uind)=units_output.MECIIthetaPL_all_run{u}.r;
        mu2MECtheta_all_run(uind)=units_output.MECIIthetaPL_all_run{u}.mu;
        
        r2LMtheta_all_run(uind) = units_output2.LMthetaPL_all_run{u}.r; 
        mu2LMtheta_all_run(uind) = units_output2.LMthetaPL_all_run{u}.mu; 
        r2Moltheta_all_run(uind) = units_output2.MolthetaPL_all_run{u}.r; 
        mu2Moltheta_all_run(uind) = units_output2.MolthetaPL_all_run{u}.mu; 
        r2Hiltheta_all_run(uind) = units_output2.HilthetaPL_all_run{u}.r; 
        mu2Hiltheta_all_run(uind) = units_output2.HilthetaPL_all_run{u}.mu;
        
        r2CA1gamma_all_run(uind)=units_output.CA1gammaPL_all_run{u}.r;   
        mu2CA1gamma_all_run(uind)=units_output.CA1gammaPL_all_run{u}.mu;
        r2MECgamma_all_run(uind)=units_output.MECIIgammaPL_all_run{u}.r;
        mu2MECgamma_all_run(uind)=units_output.MECIIgammaPL_all_run{u}.mu;
        
        mFR_all_run(uind)= units_output.mFR_all_run(u);
        meanAC_all_run(uind)=units_output.meanAC_all_run(u);
        burst_all_run(uind)=units_output.burst_all_run(u);
        burstbw_all_run(uind) = units_output.burstbw_all_run(u);
        mISI_all_run(uind)=units_output.mISI_all_run(u);
        CSI_all_run(uind)=units_output.CSI_all_run(u);
        mAmp_all_run(uind)=units_output.mAmp_all_run(u);
        
        refvio_all_run(uind)= units_output.refvio_ratio_all_run(u);
        end
        
        %all running within threshold
        if isnan(units_output.mISI_run_thresh(u))
        r2CA1theta_run_thresh(uind)=NaN;   
        mu2CA1theta_run_thresh(uind)=NaN;   
        r2MECtheta_run_thresh(uind)=NaN;   
        mu2MECtheta_run_thresh(uind)=NaN;  
        
        r2LMtheta_run_thresh(uind) = NaN;
        mu2LMtheta_run_thresh(uind) = NaN;
        r2Moltheta_run_thresh(uind) = NaN;
        mu2Moltheta_run_thresh(uind) = NaN;
        r2Hiltheta_run_thresh(uind) = NaN;
        mu2Hiltheta_run_thresh(uind) = NaN;
        
        r2CA1gamma_run_thresh(uind)=NaN;   
        mu2CA1gamma_run_thresh(uind)=NaN;   
        r2MECgamma_run_thresh(uind)=NaN;   
        mu2MECgamma_run_thresh(uind)=NaN;  
        
        mFR_run_thresh(uind)= NaN;   
        meanAC_run_thresh(uind)=NaN;   
        burst_run_thresh(uind)=NaN;   
        burstbw_run_thresh(uind) =NaN;   
        mISI_run_thresh(uind)=NaN;   
        CSI_run_thresh(uind)=NaN;   
        mAmp_run_thresh(uind)=NaN;    
        
        refvio_run_thresh(uind)= NaN;
        
        elseif ~isnan(units_output.mISI_all(u)) && ECshanks(1) == 0  %if EC shank is  missing set EC PL values to NaN
        r2CA1theta_run_thresh(uind)=units_output.CA1thetaPL_run_thresh{u}.r;   
        mu2CA1theta_run_thresh(uind)=units_output.CA1thetaPL_run_thresh{u}.mu;
        r2MECtheta_run_thresh(uind)=NaN;
        mu2MECtheta_run_thresh(uind)=NaN;
        
        r2LMtheta_run_thresh(uind) = units_output2.LMthetaPL_run_thresh{u}.r; 
        mu2LMtheta_run_thresh(uind) = units_output2.LMthetaPL_run_thresh{u}.mu; 
        r2Moltheta_run_thresh(uind) = units_output2.MolthetaPL_run_thresh{u}.r; 
        mu2Moltheta_run_thresh(uind) = units_output2.MolthetaPL_run_thresh{u}.mu; 
        r2Hiltheta_run_thresh(uind) = units_output2.HilthetaPL_run_thresh{u}.r; 
        mu2Hiltheta_run_thresh(uind) = units_output2.HilthetaPL_run_thresh{u}.mu; 
        
        r2CA1gamma_run_thresh(uind)=units_output.CA1gammaPL_run_thresh{u}.r;   
        mu2CA1gamma_run_thresh(uind)=units_output.CA1gammaPL_run_thresh{u}.mu;
        r2MECgamma_run_thresh(uind)=NaN;
        mu2MECgamma_run_thresh(uind)=NaN;
        
        mFR_run_thresh(uind)= units_output.mFR_run_thresh(u);
        meanAC_run_thresh(uind)=units_output.meanAC_run_thresh(u);
        burst_run_thresh(uind)=units_output.burst_run_thresh(u);
        burstbw_run_thresh(uind) = units_output.burstbw_run_thresh(u);
        mISI_run_thresh(uind)=units_output.mISI_run_thresh(u);
        CSI_run_thresh(uind)=units_output.CSI_run_thresh(u);
        mAmp_run_thresh(uind)=units_output.mAmp_run_thresh(u);
        
        refvio_run_thresh(uind)= units_output.refvio_ratio_run_thresh(u);
        
        else
