fig_idx1 = 10;
fig_idx2 = 20;
fig_idx3 = 30;

fig_idx4 = 40;
fig_idx5 = 50;
fig_idx6 = 60;


for reg = 1:length(regions)
    region = regions{reg};
    
    if strcmp(region, 'DG') %find indices for current layer
        cells_in_layer = DG;
    elseif strcmp(region, 'CA1')
        cells_in_layer = CA1;
    end 
    
    for t = 1:length(celltypes)
        celltype = celltypes{t};
        fig_idx1 = fig_idx1 + 1;
        fig_idx2 = fig_idx2 + 1;
        fig_idx3 = fig_idx3 + 1;
        fig_idx4 = fig_idx4 + 1;
        fig_idx5 = fig_idx5 + 1;
        fig_idx6 = fig_idx6 + 1;


        if strcmp(celltype, 'excitatory')
            cells_in_type = intersect(exc, cells_in_layer);
        elseif strcmp(celltype, 'inhibitory')
            cells_in_type = intersect(inh, cells_in_layer);
        end
                
        for rs=1:length(running_states)
        running_state = running_states{rs};
        
 
            for g=1:length(groups)
                group = groups{g};

                cells_in_group = find(contains(group_ind, group));

                cells = intersect(cells_in_type, cells_in_group);
                %cells = intersect(cells_in_group, cells_in_group);


