%% Export for R

% Create a table where each unit has a row with it's region, cell type etc.
% and all measures including firing rate, phase locking etc.

Animalname = animal_ind;
Groupname = group_ind;
Sex = sex_ind;
Age_real = age_ind;
Shank = shank_ind;


for i = 1:length(animal_ind)
    if ismember(i, CA1)
        hip_reg = 'CA1';
    elseif ismember(i, DG)
        hip_reg = 'DG';
    else 
        hip_reg = 'other';
    end
    
    if ismember(i, exc)
        type = 'e';
    elseif ismember(i, inh)
        type = 'i';
    else
        type = 'w';
    end    
    
    Region{i} = hip_reg;
    CellType{i} = type;
    
end 

